# Base module providing component hierarchy and interfaces

interface IMeasurable:
    def measure(self) -> float: ...

class Component:
    _id: int

    def __init__(self, id: int):
        self._id = id

    @virtual
    def get_info(self) -> str:
        return f"Component-{self._id}"

